class Solution {
    public int subarrayGCD(int[] nums, int k) {
        int count = 0;
        for (int i = 0; i < nums.length; i++) {
            int gcd = nums[i];
            if (gcd == k) count++;
            for (int j = i + 1; j < nums.length; j++) {
                gcd = gcd(gcd, nums[j]);
                if (gcd == k) count++;
                if (gcd < k) break;
            }
        }
        return count;
    }

    private int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
}
